import requests
import json
import sys
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth


class RabbitMQManager:
    def __init__(self, host: str = 'localhost', port: int = 15672, 
                 username: str = 'guest', password: str = 'guest'):
        self.base_url = f'http://{host}:{port}/api'
        self.auth = HTTPBasicAuth(username, password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f'{self.base_url}/{endpoint}'
        headers = {'Content-Type': 'application/json'}
        
        try:
            if method == 'GET':
                response = self.session.get(url, headers=headers)
            elif method == 'PUT':
                response = self.session.put(url, headers=headers, 
                                           data=json.dumps(data) if data else None)
            elif method == 'DELETE':
                response = self.session.delete(url, headers=headers)
            elif method == 'POST':
                response = self.session.post(url, headers=headers, 
                                            data=json.dumps(data) if data else None)
            
            return response
        except requests.exceptions.RequestException as e:
            print(f"Request failed: {e}")
            sys.exit(1)
    
    def create_vhost(self, vhost_name: str) -> bool:
        print(f"Creating virtual host: {vhost_name}")
        response = self._request('PUT', f'vhosts/{vhost_name}')
        
        if response.status_code in [201, 204]:
            print(f"✓ Virtual host '{vhost_name}' created successfully")
            return True
        elif response.status_code == 404:
            print(f"✗ Failed to create vhost: Management API not available")
            return False
        else:
            print(f"✗ Failed to create vhost: {response.status_code} - {response.text}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f"Deleting virtual host: {vhost_name}")
        response = self._request('DELETE', f'vhosts/{vhost_name}')
        
        if response.status_code == 204:
            print(f"✓ Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete vhost: {response.status_code}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        response = self._request('GET', 'vhosts')
        
        if response.status_code == 200:
            vhosts = response.json()
            print(f"\nExisting virtual hosts ({len(vhosts)}):")
            for vhost in vhosts:
                print(f"  - {vhost['name']}")
            return vhosts
        else:
            print(f"✗ Failed to list vhosts: {response.status_code}")
            return []
    
    def create_user(self, username: str, password: str, tags: str = '') -> bool:
        print(f"Creating user: {username}")
        data = {
            'password': password,
            'tags': tags
        }
        response = self._request('PUT', f'users/{username}', data)
        
        if response.status_code in [201, 204]:
            print(f"✓ User '{username}' created successfully")
            return True
        else:
            print(f"✗ Failed to create user: {response.status_code} - {response.text}")
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f"Deleting user: {username}")
        response = self._request('DELETE', f'users/{username}')
        
        if response.status_code == 204:
            print(f"✓ User '{username}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete user: {response.status_code}")
            return False
    
    def list_users(self) -> List[Dict]:
        response = self._request('GET', 'users')
        
        if response.status_code == 200:
            users = response.json()
            print(f"\nExisting users ({len(users)}):")
            for user in users:
                print(f"  - {user['name']} (tags: {user.get('tags', 'none')})")
            return users
        else:
            print(f"✗ Failed to list users: {response.status_code}")
            return []
    
    def set_permissions(self, vhost: str, username: str, 
                       configure: str = '.*', write: str = '.*', 
                       read: str = '.*') -> bool:
        print(f"Setting permissions for user '{username}' on vhost '{vhost}'")
        data = {
            'configure': configure,
            'write': write,
            'read': read
        }
        response = self._request('PUT', f'permissions/{vhost}/{username}', data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Permissions set successfully")
            print(f"  Configure: {configure}")
            print(f"  Write: {write}")
            print(f"  Read: {read}")
            return True
        else:
            print(f"✗ Failed to set permissions: {response.status_code} - {response.text}")
            return False
    
    def get_permissions(self, vhost: str, username: str) -> Optional[Dict]:
        response = self._request('GET', f'permissions/{vhost}/{username}')
        
        if response.status_code == 200:
            return response.json()
        else:
            return None
    
    def list_permissions(self, vhost: Optional[str] = None, 
                        username: Optional[str] = None) -> List[Dict]:
        if vhost:
            endpoint = f'vhosts/{vhost}/permissions'
        elif username:
            endpoint = f'users/{username}/permissions'
        else:
            endpoint = 'permissions'
        
        response = self._request('GET', endpoint)
        
        if response.status_code == 200:
            permissions = response.json()
            print(f"\nPermissions:")
            for perm in permissions:
                print(f"  User: {perm['user']}, VHost: {perm['vhost']}")
                print(f"    Configure: {perm['configure']}")
                print(f"    Write: {perm['write']}")
                print(f"    Read: {perm['read']}")
            return permissions
        else:
            print(f"✗ Failed to list permissions: {response.status_code}")
            return []
    
    def delete_permissions(self, vhost: str, username: str) -> bool:
        print(f"Deleting permissions for user '{username}' on vhost '{vhost}'")
        response = self._request('DELETE', f'permissions/{vhost}/{username}')
        
        if response.status_code == 204:
            print(f"✓ Permissions deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete permissions: {response.status_code}")
            return False
    
    def set_topic_permissions(self, vhost: str, username: str, 
                             exchange: str, write: str = '.*', 
                             read: str = '.*') -> bool:
        print(f"Setting topic permissions for user '{username}' on vhost '{vhost}'")
        data = {
            'exchange': exchange,
            'write': write,
            'read': read
        }
        response = self._request('PUT', f'topic-permissions/{vhost}/{username}', data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Topic permissions set successfully")
            return True
        else:
            print(f"✗ Failed to set topic permissions: {response.status_code}")
            return False
    
    def create_exchange(self, vhost: str, exchange_name: str, 
                       exchange_type: str = 'topic', 
                       durable: bool = True) -> bool:
        print(f"Creating exchange '{exchange_name}' on vhost '{vhost}'")
        data = {
            'type': exchange_type,
            'durable': durable,
            'auto_delete': False
        }
        response = self._request('PUT', f'exchanges/{vhost}/{exchange_name}', data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Exchange '{exchange_name}' created successfully")
            return True
        else:
            print(f"✗ Failed to create exchange: {response.status_code}")
            return False
    
    def create_queue(self, vhost: str, queue_name: str, 
                    durable: bool = True) -> bool:
        print(f"Creating queue '{queue_name}' on vhost '{vhost}'")
        data = {
            'durable': durable,
            'auto_delete': False
        }
        response = self._request('PUT', f'queues/{vhost}/{queue_name}', data)
        
        if response.status_code in [201, 204]:
            print(f"✓ Queue '{queue_name}' created successfully")
            return True
        else:
            print(f"✗ Failed to create queue: {response.status_code}")
            return False
    
    def setup_multi_tenant_environment(self, tenants: List[Dict]) -> None:
        print("=" * 60)
        print("Setting up multi-tenant RabbitMQ environment")
        print("=" * 60)
        
        for tenant in tenants:
            tenant_name = tenant['name']
            vhost_name = tenant.get('vhost', f'vhost_{tenant_name}')
            users = tenant.get('users', [])
            
            print(f"\n>>> Processing tenant: {tenant_name}")
            print("-" * 60)
            
            # Create vhost
            self.create_vhost(vhost_name)
            
            # Create users and set permissions
            for user_config in users:
                username = user_config['username']
                password = user_config['password']
                tags = user_config.get('tags', '')
                permissions = user_config.get('permissions', {})
                
                self.create_user(username, password, tags)
                
                configure = permissions.get('configure', '.*')
                write = permissions.get('write', '.*')
                read = permissions.get('read', '.*')
                
                self.set_permissions(vhost_name, username, configure, write, read)
            
            # Create exchanges if specified
            exchanges = tenant.get('exchanges', [])
            for exchange_config in exchanges:
                exchange_name = exchange_config['name']
                exchange_type = exchange_config.get('type', 'topic')
                durable = exchange_config.get('durable', True)
                self.create_exchange(vhost_name, exchange_name, exchange_type, durable)
            
            # Create queues if specified
            queues = tenant.get('queues', [])
            for queue_config in queues:
                queue_name = queue_config['name']
                durable = queue_config.get('durable', True)
                self.create_queue(vhost_name, queue_name, durable)
        
        print("\n" + "=" * 60)
        print("Multi-tenant setup completed")
        print("=" * 60)


